  ('generalpolice-94737317-moex-00142', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關粉塵爆炸的最小發火能量，下列敘述何者錯誤？', '["大氣中水分越高，最小發火能量越高", "粉塵粒徑越大，最小發火能量越高", "粉塵濃度越高，最小發火能量越高", "粉塵爆炸的最小發火能量約為10～100mJ"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "64ee3a1108c8", "answer_pdf_sha1": "aa7f41b2bdc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
