  ('generalpolice-94737317-moex-00144', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '鑄造工廠內熔化的鐵落入地上積水灘，瞬間發生爆炸，此種現象稱為下列何者？', '["分解爆炸", "化學爆炸", "水蒸氣爆炸", "混合爆炸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "64ee3a1108c8", "answer_pdf_sha1": "aa7f41b2bdc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00145', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關爆炸危險性評估參數，下列敘述何者正確？', '["爆炸範圍越大越危險", "爆炸下限值越高越危險", "最小著火能量越大越危險", "閃火點越高越危險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "64ee3a1108c8", "answer_pdf_sha1": "aa7f41b2bdc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00146', 'generalpolice-94737317', 'generalpolice-94737317-moex-114-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '散布於空氣中之微粒子表面產生氧化反應，且發火源影響粒子表面加熱、分解、蒸發而產生可燃 性氣體，並與周圍空氣形成爆炸性混合物，其引起之爆炸稱為：', '["蒸氣爆炸", "火藥爆炸", "分解爆炸", "粉塵爆炸"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "64ee3a1108c8", "answer_pdf_sha1": "aa7f41b2bdc9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "402", "s": "1108", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00147', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '下列文句中，「」內成語使用正確的是：', '["水果盛產，「瓜田李下」令人欣喜", "襲用他人創意，真是「拾人牙慧」", "山林間的「兩袖清風」，涼爽宜人", "店內貨架，商品堆積「間不容髮」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00148', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「一般而言，演講稿可以適時出現驚嘆號來強化語氣，但公開信件的重點在於『持 平且冷靜地陳述某件事』，驚嘆號不僅不利閱讀，通篇強烈的語氣也會讓讀者情緒 波動，甚至產生疑惑。」 根據上文，下列選項何者正確？', '["演講稿和公開信件的寫作方式相同", "演講稿出現驚嘆號，容易令人疑惑", "強烈語氣常有助於讓讀者共鳴", "公開信件宜冷靜，不應使用驚嘆號"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00149', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「Z世代發現，儘管黑膠唱片和卡帶是不存在於生命經驗中的古老事物，對他們而 言，卻是全新的、美好的聆賞音樂的方式。與之類似，對於個體來說，創造『新』 的體驗才是第一要務，而體驗來源是不是來自舊時代並不重要。」 下列敘述，何者最符合本文意旨？', '["復古是對於生命美好事物的再次經歷", "對Z世代來說，復古也是一種新體驗", "新是復古的本質，也是Z世代的追求", "舊時代提供Z世代對未來有美好憧憬"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00150', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「心理學家愛德華．桑代克曾透過『迷箱實驗』，提出工具性制約理論。實驗中他 將空腹的貓放入以細繩或踏板控制門開閉的箱子中，並在箱前放食物。想走出箱子 拿取食物的貓不斷嘗試各種方法，在偶然情況下拉到繩子或踩到踏板，最後吃到食 物。反覆嘗試數次後，脫困時間逐漸縮短。這便是『試行錯誤學習』，桑代克據此 提出連結學習三定律——練習律：練習次數會影響個體和刺激之間連結的強弱。準 備律：刺激與反應之間的連結和個體本身的身心狀態有關。效果律：反應後獲得的 結果將會強化或弱化往後是否做出相同反應的機會。」 根據上文，下列選項何者正確？', '["「試行錯誤學習」是依據效果律的原理進行", "由「迷箱實驗」可知，貓咪的智商高於人類", "上述實驗拿掉作為工具的箱子並不影響結果", "滿足學習者需求以提高學習成效屬於練習律 90110"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00151', 'generalpolice-94737317', 'generalpolice-94737317-moex-113-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「由於翻譯羅曼史在一九七○、一九八○年代越趨產業化，依賴大量的譯者在短時 間內產出大量文本，因此在《著作權法》通過之後，取得版權的成本對這種薄利多 銷的類型小說造成壓力，盛極一時的翻譯羅曼史在一九九○年代迅速消退，而為本 土羅曼史所取代。」 根據上文，下列選項何者正確？', '["本土羅曼史自一九七○年代就十分興盛", "翻譯羅曼史至一九九○年代仍大量生產", "《著作權法》的修訂影響臺灣出版產業", "羅曼史不分本土或外來一直受大眾歡迎"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:46+00:00", "source_pdf_sha1": "9fcf8118fb21", "answer_pdf_sha1": "8c205779accb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "402", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
